import { jsx, jsxs } from 'react/jsx-runtime';
import { IconButton } from '../IconButton/IconButton.js';
import '../../helpers/popupsContext.js';
import { useDeviceSize } from '../../helpers/use-device-size.js';
import { useComponentDidMount } from '../../helpers/use-component-did-mount.js';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import { snackbarTextFontLineHeight, snackbarTextMarginTop, snackbarElasticTextMarginBottom } from '@beeline/design-tokens/js/tokens/components/snackbar';
import { useRef, useState, useEffect } from 'react';
import { classNames } from '../../helpers/classnames.js';
import { Button } from '../Button/Button.js';
import '../Button/ProgressButton/ProgressButton.js';
import { Typography } from '../Typography/Typography.js';

const Snackbar = ({ open = false, message, delay = 3000, onClose, action, closeButton = false, horizontal = 'right', vertical = 'bottom', variant = 'elastic', className, }) => {
    const isComponentMounted = useComponentDidMount();
    const { isExtraSmallDevice } = useDeviceSize();
    const onCloseRef = useRef(onClose);
    onCloseRef.current = onClose;
    const _horizontal = isExtraSmallDevice ? 'center' : horizontal;
    // Используем проп vertical независимо от размера устройства
    const _vertical = vertical;
    const snackbarRef = useRef(null);
    const [multilineText, setTextState] = useState(false);
    // todo если текст многострочный, то стилистика меняется, наверное, можно убрать из зависимостей всё, кроме isComponentMounted
    // так как компонент должен быть статичный после отображения, но пока так
    useEffect(() => {
        const blockHeight = Number.parseInt(snackbarTextFontLineHeight) +
            Number.parseInt(snackbarTextMarginTop) +
            Number.parseInt(snackbarElasticTextMarginBottom);
        setTextState(snackbarRef?.current?.offsetHeight > blockHeight);
    }, [isComponentMounted, open, message, action, variant]);
    const actionButton = action && (jsx(Button, { variant: "plain", size: "small", className: "dsb_snackbar-body-action", onClick: action?.onClick, children: action?.label || 'Закрыть' }));
    const [isOpen, setIsOpen] = useState(open);
    const [isVisible, setIsVisible] = useState(open);
    const transitionEndRef = useRef(false);
    // Обновляем состояния при изменении пропса open
    useEffect(() => {
        if (open) {
            setIsVisible(true);
            setIsOpen(true);
            transitionEndRef.current = false;
        }
        else {
            // Только меняем isOpen, isVisible изменится после перехода
            setIsOpen(false);
        }
    }, [open]);
    // Обработчик завершения перехода
    useEffect(() => {
        const node = snackbarRef.current;
        if (!node) {
            return;
        }
        const handleTransitionEnd = (event) => {
            if (event.propertyName === 'opacity' && !isOpen) {
                // Скрываем компонент только после завершения перехода
                setIsVisible(false);
            }
        };
        node.addEventListener('transitionend', handleTransitionEnd);
        return () => node.removeEventListener('transitionend', handleTransitionEnd);
    }, [isOpen]);
    // Автоматическое закрытие по таймеру
    useEffect(() => {
        if (isOpen && delay) {
            const timer = setTimeout(() => {
                closeAction();
            }, delay);
            return () => clearTimeout(timer);
        }
    }, [delay, isOpen]);
    const closeAction = () => {
        // Предотвращаем повторное закрытие
        if (!isOpen) {
            return;
        }
        onCloseRef.current?.();
        setIsOpen(false);
    };
    // Если компонент не должен быть видимым, возвращаем undefined
    if (!isVisible) {
        return;
    }
    return (jsx("div", { className: "dsb_snackbar-wrapper", "data-testid": "Snackbar", children: jsx("div", { role: "alert", "aria-live": "polite", "aria-atomic": "true", "aria-hidden": !isOpen, ref: snackbarRef, className: classNames('dsb_snackbar', isOpen ? 'dsb_snackbar__open' : 'dsb_snackbar__closing', `dsb_snackbar__${_horizontal}`, `dsb_snackbar__${_vertical}`, 'inverseTheme', `dsb_snackbar__${variant}`, isExtraSmallDevice && 'dsb_snackbar-mobile', multilineText && 'dsb_snackbar__multiline', className), children: jsxs("div", { className: "dsb_snackbar-body", children: [jsxs("div", { className: "dsb_snackbar-body_content-line", children: [jsx(Typography, { variant: "body3", className: classNames('dsb_snackbar-body-message', action && 'dsb_snackbar-body-message__with-action', `dsb_snackbar-body-message__${variant}`, closeButton && 'dsb_snackbar-body-message__with-close'), children: message }), actionButton] }), closeButton && (jsx("div", { className: "dsb_snackbar-body_close-block", children: jsx(IconButton, { iconName: Icons.Close, onClick: closeAction }) }))] }) }) }));
};

export { Snackbar };
